import { afterEach, beforeEach, describe, expect, it, vi } from "vitest";
const mockClearActiveStudioSession = vi.fn();
const mockUpdateActiveStudioSession = vi.fn();
const mockReadActiveStudioSession = vi.fn().mockReturnValue(null);
vi.mock("../activeStudioSession.js", () => ({
    clearActiveStudioSession: (...args) => mockClearActiveStudioSession(...args),
    updateActiveStudioSession: (...args) => mockUpdateActiveStudioSession(...args),
    readActiveStudioSession: (...args) => mockReadActiveStudioSession(...args),
}));
// biome-ignore lint/suspicious/noExplicitAny: test capture of subscribe callbacks
let capturedOnEvent = null;
// biome-ignore lint/suspicious/noExplicitAny: test capture of subscribe callbacks
let _capturedOnError = null;
const mockSubscribeAbort = vi.fn();
const mockSubscribe = vi
    .fn()
    .mockImplementation((_sessionId, onEvent, onError) => {
    capturedOnEvent = onEvent;
    _capturedOnError = onError;
    return { abort: mockSubscribeAbort, done: new Promise(() => { }) };
});
const mockChannelClose = vi.fn().mockResolvedValue(undefined);
const mockChannelDestroy = vi.fn();
const mockForceCloseWindow = vi.fn();
const mockResolveChannel = vi.fn().mockResolvedValue({
    subscribe: (...args) => mockSubscribe(...args),
    close: (...args) => mockChannelClose(...args),
    forceCloseWindow: (...args) => mockForceCloseWindow(...args),
    destroy: (...args) => mockChannelDestroy(...args),
});
vi.mock("../studioChannel.js", () => ({
    resolveChannel: (...args) => mockResolveChannel(...args),
}));
let mockAuthenticated = true;
vi.mock("../config.js", () => ({
    getConfig: () => ({
        serviceUrl: "https://test.invalid",
        apiKey: mockAuthenticated ? "test-key" : null,
    }),
    hasCredentials: () => mockAuthenticated,
}));
const mockEmitJson = vi.fn();
vi.mock("../output.js", () => ({
    emitJson: (...args) => mockEmitJson(...args),
}));
const SESSION = "11111111-1111-4111-8111-111111111111";
const KILL_DELAY_MS = 2_500;
const CONFIRM_TIMEOUT_MS = 8_000;
const GRACE_MS = 10_000;
describe("runCloseStudio", () => {
    let exitMock;
    let killMock;
    let savedArgv;
    beforeEach(() => {
        capturedOnEvent = null;
        _capturedOnError = null;
        mockAuthenticated = true;
        mockEmitJson.mockClear();
        mockClearActiveStudioSession.mockClear();
        mockUpdateActiveStudioSession.mockClear();
        mockReadActiveStudioSession.mockReset().mockReturnValue(null);
        mockChannelClose.mockClear();
        mockChannelDestroy.mockClear();
        mockForceCloseWindow.mockClear();
        mockResolveChannel.mockClear();
        mockSubscribe.mockClear();
        mockSubscribeAbort.mockClear();
        mockResolveChannel.mockResolvedValue({
            subscribe: (...args) => mockSubscribe(...args),
            close: (...args) => mockChannelClose(...args),
            forceCloseWindow: (...args) => mockForceCloseWindow(...args),
            destroy: (...args) => mockChannelDestroy(...args),
        });
        exitMock = vi
            .spyOn(process, "exit")
            .mockImplementation((() => undefined));
        killMock = vi
            .spyOn(process, "kill")
            .mockImplementation((() => true));
        savedArgv = process.argv;
        process.argv = ["node", "closeStudio.js"];
    });
    afterEach(() => {
        process.argv = savedArgv;
        exitMock.mockRestore();
        killMock.mockRestore();
        vi.unstubAllGlobals();
    });
    it("subscribes via channel and clears only on a window-closed that survives the grace", async () => {
        vi.useFakeTimers();
        try {
            mockReadActiveStudioSession.mockReturnValue({
                sessionId: SESSION,
                serviceUrl: "https://test.invalid",
                pollerPid: process.pid,
                openedAt: "2026-01-01T00:00:00.000Z",
            });
            const { runCloseStudio } = await import("./closeStudio.js");
            const run = runCloseStudio();
            await vi.advanceTimersByTimeAsync(0);
            expect(mockSubscribe).toHaveBeenCalledWith(SESSION, expect.any(Function), expect.any(Function));
            expect(mockChannelClose).toHaveBeenCalled();
            capturedOnEvent({ type: "studio:session-ended", data: {} });
            capturedOnEvent({ type: "studio:session-closed", data: {} });
            capturedOnEvent({ type: "studio:window-closed", data: {} });
            await vi.advanceTimersByTimeAsync(GRACE_MS - 1);
            expect(mockClearActiveStudioSession).not.toHaveBeenCalled();
            await vi.advanceTimersByTimeAsync(2);
            await run;
            expect(mockUpdateActiveStudioSession).toHaveBeenCalledWith({
                windowState: "closed",
            });
            expect(killMock).not.toHaveBeenCalled();
        }
        finally {
            vi.useRealTimers();
        }
    });
    it("does NOT clear when the window-closed was a refresh (session-started refutes it)", async () => {
        vi.useFakeTimers();
        try {
            mockReadActiveStudioSession.mockReturnValue({
                sessionId: SESSION,
                serviceUrl: "https://test.invalid",
                pollerPid: process.pid,
                openedAt: "2026-01-01T00:00:00.000Z",
            });
            const { runCloseStudio } = await import("./closeStudio.js");
            const run = runCloseStudio();
            await vi.advanceTimersByTimeAsync(0);
            expect(capturedOnEvent).not.toBeNull();
            capturedOnEvent({ type: "studio:window-closed", data: {} });
            capturedOnEvent({ type: "studio:session-started", data: {} });
            await vi.advanceTimersByTimeAsync(CONFIRM_TIMEOUT_MS + GRACE_MS + 1);
            await run;
            expect(mockClearActiveStudioSession).not.toHaveBeenCalled();
        }
        finally {
            vi.useRealTimers();
        }
    });
    it("SIGTERMs the recorded window pid when no confirmation arrives, and keeps the pointer", async () => {
        vi.useFakeTimers();
        try {
            mockReadActiveStudioSession.mockReturnValue({
                sessionId: SESSION,
                serviceUrl: "https://test.invalid",
                pollerPid: 123,
                openedAt: "2026-01-01T00:00:00.000Z",
                windowPid: 4242,
            });
            const { runCloseStudio } = await import("./closeStudio.js");
            const run = runCloseStudio();
            await vi.advanceTimersByTimeAsync(0);
            expect(capturedOnEvent).not.toBeNull();
            expect(mockChannelClose).toHaveBeenCalled();
            await vi.advanceTimersByTimeAsync(KILL_DELAY_MS - 1);
            expect(killMock).not.toHaveBeenCalled();
            expect(mockForceCloseWindow).not.toHaveBeenCalled();
            await vi.advanceTimersByTimeAsync(2);
            expect(killMock).toHaveBeenCalledWith(4242, "SIGTERM");
            expect(mockForceCloseWindow).toHaveBeenCalledWith(SESSION);
            await vi.advanceTimersByTimeAsync(CONFIRM_TIMEOUT_MS);
            await run;
            expect(mockClearActiveStudioSession).not.toHaveBeenCalled();
            expect(killMock).toHaveBeenCalledWith(123, "SIGTERM");
        }
        finally {
            vi.useRealTimers();
        }
    });
    it("force-closes immediately on session-closed, before the kill-delay backstop", async () => {
        vi.useFakeTimers();
        try {
            mockReadActiveStudioSession.mockReturnValue({
                sessionId: SESSION,
                serviceUrl: "https://test.invalid",
                pollerPid: 123,
                openedAt: "2026-01-01T00:00:00.000Z",
                windowPid: 4242,
            });
            const { runCloseStudio } = await import("./closeStudio.js");
            const run = runCloseStudio();
            await vi.advanceTimersByTimeAsync(0);
            expect(capturedOnEvent).not.toBeNull();
            // session-closed (close page reached) arrives before the kill-delay backstop.
            capturedOnEvent({ type: "studio:session-closed", data: {} });
            await vi.advanceTimersByTimeAsync(0);
            expect(mockForceCloseWindow).toHaveBeenCalledWith(SESSION);
            expect(killMock).toHaveBeenCalledWith(4242, "SIGTERM");
            const forceCalls = mockForceCloseWindow.mock.calls.length;
            // The backstop must not double-fire the force-close.
            await vi.advanceTimersByTimeAsync(KILL_DELAY_MS + CONFIRM_TIMEOUT_MS + GRACE_MS + 1);
            await run;
            expect(mockForceCloseWindow.mock.calls.length).toBe(forceCalls);
        }
        finally {
            vi.useRealTimers();
        }
    });
    it("does not kill when the pointer was re-bound to a different session mid-close", async () => {
        vi.useFakeTimers();
        try {
            mockReadActiveStudioSession
                .mockReturnValueOnce({
                sessionId: SESSION,
                serviceUrl: "https://test.invalid",
                pollerPid: 123,
                openedAt: "2026-01-01T00:00:00.000Z",
                windowPid: 4242,
            })
                .mockReturnValue({
                sessionId: "22222222-2222-4222-8222-222222222222",
                serviceUrl: "https://test.invalid",
                pollerPid: 123,
                openedAt: "2026-01-01T00:00:01.000Z",
                windowPid: 4242,
            });
            const { runCloseStudio } = await import("./closeStudio.js");
            const run = runCloseStudio();
            await vi.advanceTimersByTimeAsync(0);
            expect(capturedOnEvent).not.toBeNull();
            await vi.advanceTimersByTimeAsync(KILL_DELAY_MS + 1);
            await vi.advanceTimersByTimeAsync(CONFIRM_TIMEOUT_MS);
            await run;
            expect(killMock).not.toHaveBeenCalled();
            expect(mockClearActiveStudioSession).not.toHaveBeenCalled();
        }
        finally {
            vi.useRealTimers();
        }
    });
    it("exits quietly when the close push fails (session already gone)", async () => {
        mockReadActiveStudioSession.mockReturnValue({
            sessionId: SESSION,
            serviceUrl: "https://test.invalid",
            pollerPid: process.pid,
            openedAt: "2026-01-01T00:00:00.000Z",
        });
        mockChannelClose.mockRejectedValueOnce(new Error("403"));
        exitMock.mockImplementation(((code) => {
            throw new Error(`exit:${code}`);
        }));
        const { runCloseStudio } = await import("./closeStudio.js");
        await expect(runCloseStudio()).rejects.toThrow("exit:0");
        expect(mockEmitJson).toHaveBeenCalledWith({
            event: "close-skipped",
            sessionId: SESSION,
            reason: "session-gone",
        });
        expect(mockClearActiveStudioSession).not.toHaveBeenCalled();
        expect(killMock).not.toHaveBeenCalled();
    });
    it("resolves the session from the disk pointer, passes the message through, and reaps the poller pid on a confirmed close", async () => {
        vi.useFakeTimers();
        try {
            process.argv = ["node", "closeStudio.js", "Done!"];
            mockReadActiveStudioSession.mockReturnValue({
                sessionId: SESSION,
                serviceUrl: "https://test.invalid",
                pollerPid: 99999,
                openedAt: "2026-01-01T00:00:00.000Z",
            });
            const { runCloseStudio } = await import("./closeStudio.js");
            const run = runCloseStudio();
            await vi.advanceTimersByTimeAsync(0);
            expect(mockChannelClose).toHaveBeenCalledWith(SESSION, "Done!");
            capturedOnEvent({ type: "studio:window-closed", data: {} });
            await vi.advanceTimersByTimeAsync(GRACE_MS + 1);
            await run;
            expect(killMock).toHaveBeenCalledWith(99999, "SIGTERM");
            expect(mockUpdateActiveStudioSession).toHaveBeenCalledWith({
                windowState: "closed",
            });
            expect(mockEmitJson).toHaveBeenCalledWith({
                event: "closed",
                sessionId: SESSION,
            });
        }
        finally {
            vi.useRealTimers();
        }
    });
    it("never SIGTERMs its own pid when the pointer was written by this process", async () => {
        vi.useFakeTimers();
        try {
            process.argv = ["node", "closeStudio.js"];
            mockReadActiveStudioSession.mockReturnValue({
                sessionId: SESSION,
                serviceUrl: "https://test.invalid",
                pollerPid: process.pid,
                openedAt: "2026-01-01T00:00:00.000Z",
            });
            const { runCloseStudio } = await import("./closeStudio.js");
            const run = runCloseStudio();
            await vi.advanceTimersByTimeAsync(0);
            capturedOnEvent({ type: "studio:window-closed", data: {} });
            await vi.advanceTimersByTimeAsync(GRACE_MS + 1);
            await run;
            expect(killMock).not.toHaveBeenCalled();
            expect(mockUpdateActiveStudioSession).toHaveBeenCalledWith({
                windowState: "closed",
            });
        }
        finally {
            vi.useRealTimers();
        }
    });
    it("no-ops (exit 0, no close push) when no pointer exists", async () => {
        exitMock.mockImplementation(((code) => {
            throw new Error(`exit:${code}`);
        }));
        const { runCloseStudio } = await import("./closeStudio.js");
        await expect(runCloseStudio()).rejects.toThrow("exit:0");
        expect(mockEmitJson).toHaveBeenCalledWith({ event: "no-active-studio" });
        expect(mockChannelClose).not.toHaveBeenCalled();
        expect(killMock).not.toHaveBeenCalled();
    });
    it("no-ops without credentials but still reaps a lingering poller", async () => {
        mockAuthenticated = false;
        mockReadActiveStudioSession.mockReturnValue({
            sessionId: SESSION,
            serviceUrl: "https://test.invalid",
            pollerPid: 77777,
            openedAt: "2026-01-01T00:00:00.000Z",
        });
        exitMock.mockImplementation(((code) => {
            throw new Error(`exit:${code}`);
        }));
        const { runCloseStudio } = await import("./closeStudio.js");
        await expect(runCloseStudio()).rejects.toThrow("exit:0");
        expect(mockEmitJson).toHaveBeenCalledWith({
            event: "close-skipped",
            sessionId: SESSION,
            reason: "not-authenticated",
        });
        expect(killMock).toHaveBeenCalledWith(77777, "SIGTERM");
        expect(mockChannelClose).not.toHaveBeenCalled();
        expect(mockClearActiveStudioSession).not.toHaveBeenCalled();
    });
});
